graphql metrics anza-xyz/rust: gh api graphql -f query=
query($owner:String!, $name:String!, $sinceGit:GitTimestamp!, $untilGit:GitTimestamp!, $sinceDate:DateTime!) {
  repository(owner:$owner, name:$name) {
    id
    nameWithOwner
    isArchived
    isFork
    isTemplate
    primaryLanguage { name }
    defaultBranchRef {
      name
      target {
        ... on Commit {
          history(since:$sinceGit, until:$untilGit) { totalCount }
        }
      }
    }
    pullRequests(first:100, orderBy:{field:UPDATED_AT, direction:DESC}) {
      totalCount
      nodes {
        number
        title
        state
        isDraft
        createdAt
        updatedAt
        mergedAt
        closedAt
        changedFiles
        comments { totalCount }
        commits { totalCount }
        author { login __typename }
      }
    }
    issues(first:100, filterBy:{since:$sinceDate}, orderBy:{field:UPDATED_AT, direction:DESC}) {
      totalCount
      nodes {
        createdAt
        updatedAt
        comments { totalCount }
      }
    }
    releases(first:50, orderBy:{field:CREATED_AT, direction:DESC}) {
      totalCount
      nodes {
        tagName
        publishedAt
        createdAt
      }
    }
  }
  rateLimit { cost remaining }
}
